void qMRMLSliceControllerWidget::setSliceModelFOV(int index, double fov)
{
  double oldFov[3];
  this->mrmlSliceNode()->GetUVWExtents(oldFov);
  if (qAbs(oldFov[index] - fov) < 0.01)
